(async function () {
    const manifest = global.get("manifest");
    const gateway_id = global.get("gateway_id");

    node.warn(manifest);

    if (!manifest || !manifest.config || !manifest.config.plant || !manifest.config.plant.areas) {
        node.warn("Manifesto inválido no Messaging. Estrutura de Planta/Áreas ausente.");
        return;
    }

    let modbus_clients = global.get("modbus_clients") || {};
    let opcua_clients = global.get("opcua_clients") || {};

    for (let id in modbus_clients) {
        if (modbus_clients[id].client && modbus_clients[id].client.isOpen) {
            modbus_clients[id].client.close();
        }
    }

    for (let id in opcua_clients) {
        try {
            if (opcua_clients[id].session) await opcua_clients[id].session.close();
            if (opcua_clients[id].client) await opcua_clients[id].client.disconnect();
        } catch (erro) {
            node.warn(`[Messaging] Erro ao fechar OPC UA antigo de ${id}: ${erro.message}`);
        }
    }

    modbus_clients = {};
    opcua_clients = {};
    const areas = manifest.config.plant.areas;

    for (const areaId of Object.keys(areas)) {
        const lines = areas[areaId].lines || {};
        for (const lineId of Object.keys(lines)) {
            const devices = lines[lineId].devices || {};
            for (const deviceId of Object.keys(devices)) {
                const dev = devices[deviceId];
                if (dev.enabled !== true) continue;

                const protocol = dev.connection.protocol;

                if (protocol === "modbus_tcp") {
                    const client = new ModbusRTU();
                    try {
                        await client.connectTCP(dev.connection.host, { port: dev.connection.port || 502 });
                        client.setID(dev.connection.unit_id || 1);

                        modbus_clients[deviceId] = {
                            client: client,
                            config: dev,
                            gateway_id: gateway_id
                        };
                        node.warn(`[Messaging] Conexão MODBUS estabelecida com ${deviceId}`);
                    } catch (erro) {
                        node.warn(`[Messaging] Erro ao conectar MODBUS com ${deviceId}: ${erro.message}`);
                    }
                }

                else if (protocol === "opc_ua") {
                    try {
                        const client = opcua.OPCUAClient.create({
                            endpointMustExist: false,
                            connectionStrategy: {
                                maxRetry: 2,
                                initialDelay: 1000,
                                maxDelay: 2000
                            }
                        });

                        await client.connect(dev.connection.endpoint_url);
                        const session = await client.createSession();

                        opcua_clients[deviceId] = {
                            client: client,
                            session: session,
                            config: dev,
                            gateway_id: gateway_id
                        };
                        node.warn(`[Messaging] Conexão OPC UA estabelecida com ${deviceId}`);
                    } catch (erro) {
                        node.warn(`[Messaging] Erro ao conectar OPC UA com ${deviceId}: ${erro.message}`);
                    }
                }
            }
        }
    }

    global.set("modbus_clients", modbus_clients);
    global.set("opcua_clients", opcua_clients);

    node.warn(`Clientes ativos -> Modbus: ${Object.keys(modbus_clients).length} | OPC UA: ${Object.keys(opcua_clients).length}`);

    msg.payload = "Running";
    node.send(msg);;

})();

return null;

const active_clients = global.get("modbus_clients");
if (!active_clients) return null;

let timers = context.get("timersAtivos") || {};
for(let key in timers) {
    clearInterval(timers[key]);
}
timers = {};

Object.keys(active_clients).forEach((deviceId) => {
    const { client, config, gateway_id } = active_clients[deviceId]

    const scanRate = config.connection.scan_rate_ms || 1000;
    const metrics = config.metrics_mapping || {};

    let intervalId = setInterval(async () => {
        if (!client.isOpen) return;
        try {
            let data_payload = {};
            for (let addrKey of Object.keys(metrics)) {
                const metric = metrics[addrKey];

                let address = parseInt(addrKey);
                if (address >= 40001 && address <= 49999) address -= 40001;
                else if (address >= 30001 && address <= 39999) address -= 30001;

                let quantity = (metric.data_type === "float" || metric.data_type === "int32") ? 2 : 1;
                if (metric.data_type == "double" || metric.data_type == "int64") quantity = 4;

                let data;
                if (metric.register_type === "holding" || addrKey.startsWith("4"))
                    data = await client.readHoldingRegisters(address, quantity);
                else if (metric.register_type === "input" || addrKey.startsWith("3"))
                    data = await client.readInputRegisters(address, quantity); 

                data_payload[addrKey] = (data.data.length === 1) ? data.data[0] : data.data;
            }
            node.warn(msg.payload);

            node.send({
                payload: {
                    timestamp: Date.now(),
                    gateway_id: gateway_id,
                    source: {
                        device_id: deviceId,
                        source_protocol: config.connection.protocol
                    },
                    data: data_payload
                }
            });
        } catch (erro) {
            node.warn(`[Messaging] Erro de leitura em ${deviceId}: ${erro.message}`);
        }
    }, scanRate);

    timers[deviceId] = intervalId;
});

context.set("timersAtivos", timers);
if (active_clients.length > 0) node.status({ fill: "green", shape: "dot", text: "Lendo e processando..." });
else node.status({ fill: "pink", shape: "dot", text: "Sem clientes Modbus ativos" });

node.on("close", function () {
    let timersAtivos = context.get("timersAtivos") || {};
    for (let key in timersAtivos) clearInterval(timersAtivos[key]);
    context.set("timersAtivos", {});
});

return null;

const active_clients = global.get("opcua_clients");
if (!active_clients) return null;

let timers = context.get("timersAtivos_opcua") || {};
for(let key in timers) {
    clearInterval(timers[key]);
}
timers = {};

Object.keys(active_clients).forEach((deviceId) => {
    const { session, config, gateway_id } = active_clients[deviceId];

    const scanRate = config.connection.scan_rate_ms || 1000;
    const metrics = config.metrics_mapping || {};

    const nodesToRead = [];
    const metricKeys = Object.keys(metrics);

    metricKeys.forEach(addrKey => {
        const metric = metrics[addrKey];
        if (metric.node_id) {
            nodesToRead.push({
                nodeId: metric.node_id,
                attributeId: 13
            });
        }
    });

    if (nodesToRead.length === 0) return;

    let intervalId = setInterval(async () => {
        if (!session) return;

        try {
            const dataValues = await session.read(nodesToRead);

            let data_payload = {};

            dataValues.forEach((dataValue, index) => {
                const originalKey = metricKeys[index];

                let valor = (dataValue.statusCode && dataValue.statusCode.value === 0) 
                            ? dataValue.value.value 
                            : null; 

                data_payload[originalKey] = valor;
            });

            node.send({
                payload: {
                    timestamp: Date.now(),
                    gateway_id: gateway_id,
                    source: {
                        device_id: deviceId,
                        source_protocol: config.connection.protocol
                    },
                    data: data_payload
                }
            });

        } catch (erro) {
            node.warn(`[Messaging] Erro de leitura OPC UA em ${deviceId}: ${erro.message}`);
        }
    }, scanRate);

    timers[deviceId] = intervalId;
});

context.set("timersAtivos_opcua", timers);
if (active_clients.length > 0) {
    node.status({ fill: "blue", shape: "dot", text: "Lendo OPC UA em Bulk..." });
} else {
    node.status({ fill: "pink", shape: "dot", text: "Sem clientes OPC-UA ativos" });
}

node.on("close", function () {
    let timersAtivos = context.get("timersAtivos_opcua") || {};
    for (let key in timersAtivos) clearInterval(timersAtivos[key]);
    context.set("timersAtivos_opcua", {});
});

return null;
